// Binary map encode/decode helpers (generated by Nitrogen)
// Wire: [4B payload_len][4B count][entries: [4B key_len][key_bytes][value_bytes]]

Uint8List _nitroMapPayload(
  Map<String, dynamic> m,
  void Function(ByteData h, BytesBuilder bb, dynamic v) writeVal,
) {
  final bb = BytesBuilder();
  final hdr = ByteData(8);
  hdr.setInt32(0, m.length, Endian.little);
  bb.add(hdr.buffer.asUint8List(0, 4));
  for (final e in m.entries) {
    final k = utf8.encode(e.key);
    hdr.setInt32(0, k.length, Endian.little);
    bb.add(hdr.buffer.asUint8List(0, 4));
    bb.add(k);
    writeVal(hdr, bb, e.value);
  }
  final payload = bb.toBytes();
  final lenBuf = ByteData(4)..setInt32(0, payload.length, Endian.little);
  return Uint8List.fromList([...lenBuf.buffer.asUint8List(0, 4), ...payload]);
}

Pointer<Uint8> _nitroEncodeMapBinaryInt(Map<String, int> m, Allocator alloc) {
  final bytes = _nitroMapPayload(m, (h, bb, v) {
    bb.addByte(1);
    h.setInt64(0, v as int, Endian.little);
    bb.add(h.buffer.asUint8List(0, 8));
  });
  final ptr = alloc<Uint8>(bytes.length);
  ptr.asTypedList(bytes.length).setAll(0, bytes);
  return ptr;
}

Map<String, int> _nitroDecodeMapBinaryInt(Pointer<Uint8> ptr) {
  final payLen = ByteData.sublistView(
    ptr.asTypedList(4),
  ).getInt32(0, Endian.little);
  final bd = ByteData.sublistView(
    Uint8List.fromList((ptr + 4).asTypedList(payLen)),
  );
  int pos = 0;
  final count = bd.getInt32(pos, Endian.little);
  pos += 4;
  final result = <String, int>{};
  for (var i = 0; i < count; i++) {
    final kLen = bd.getInt32(pos, Endian.little);
    pos += 4;
    final key = utf8.decode(bd.buffer.asUint8List(pos, kLen));
    pos += kLen;
    pos += 1; // skip type tag (always 1=int64 for Map<String,int>)
    final v = bd.getInt64(pos, Endian.little);
    pos += 8;
    result[key] = v;
  }
  return result;
}

